import React, { createContext, useContext, useState, useEffect } from 'react';
import { darkTheme, lightTheme } from '../styles/theme';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  // Initialize state from local storage or default to dark
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('finify-theme');
    return savedTheme ? savedTheme === 'dark' : true;
  });

  // Effect to inject CSS variables into the document root
  useEffect(() => {
    const root = window.document.documentElement;
    const currentTheme = isDarkMode ? darkTheme : lightTheme;
    const themeName = isDarkMode ? 'dark' : 'light';

    // Apply the tokens to the DOM
    Object.entries(currentTheme).forEach(([property, value]) => {
      root.style.setProperty(property, value);
    });

    // Set data attribute for specialized CSS selectors
    root.setAttribute('data-theme', themeName);
    localStorage.setItem('finify-theme', themeName);
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode((prev) => !prev);

  return (
    <ThemeContext.Provider value={{ isDarkMode, toggleTheme, theme: isDarkMode ? darkTheme : lightTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};
